Rule.Source:
  import sailpoint.object.QueryOptions;
  import sailpoint.object.Filter;
  import sailpoint.object.Link;
  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import sailpoint.api.IdentityService;
  import org.apache.commons.logging.LogFactory;
  import org.apache.commons.logging.Log;

  private static Log logger = LogFactory.getLog("Ascension-Global-Manager-Rule");
  logger.debug("Start Ascension-Global-Manager-Rule");
  String attributeValue = null;

  IdentityService idService = new IdentityService(context);
  logger.debug("identity: " + identity);
  
  // Fix: Stop override of Manager value in SailPoint from AD-AMITA - Start...
  if(Util.nullSafeCaseInsensitiveEq(identity.getAttribute("ministry"),"AMITA Health")){
  	
  	return null ;
  }
  // Fix: Stop override of Manager value in SailPoint from AD-AMITA - End.
  
   Identity tempIdentity = null;
  List links = identity.getLinks();
  boolean found = false;
  if (links != null && !links.isEmpty()) {
    logger.debug("Got Links: " + links);
    for(Link appLink:links) {
      logger.debug("Checking for AD Links");

      if( null != appLink && null != appLink.getApplication() && Util.isNotNullOrEmpty(appLink.getApplication().getName())){

        //Midas Seeker - Provider Onboarding
        if( appLink.getApplication().getName().equalsIgnoreCase("Midas Seeker - Provider Onboarding")){

          Custom custom = context.getObjectByName(Custom.class,"Ascension-custom-generalConfiguration");
          if(custom !=null && custom.get("MidasProviderManager") !=null){
            if( (tempIdentity =  context.getObjectByName(Identity.class, custom.get("MidasProviderManager").toString())) != null){
              attributeValue = custom.get("MidasProviderManager").toString();
              //comment decache //context.decache(custom);
               //comment decache //context.decache(tempIdentity);
              found = true;
              break;
            }
          }
        }

       
       // MDStaff - Ascension
        if( Util.nullSafeCaseInsensitiveEq(appLink.getApplication().getName(),"MDStaff - Ascension") && appLink.getAttribute("Ministry_Domain") !=null ){
          String linkValue = appLink.getAttribute("Ministry_Domain").toString();
          Custom custom = context.getObjectByName(Custom.class,"Ascension-custom-generalConfiguration");
          if(Util.isNotNullOrEmpty(linkValue) && custom !=null && custom.get("MDStaff-AscensionManager") !=null && custom.get("MDStaff-AscensionManager") instanceof Map){
            String managerValue = custom.get("MDStaff-AscensionManager").get(linkValue);
            if(Util.isNotNullOrEmpty(managerValue) && (tempIdentity = context.getObjectByName(Identity.class, managerValue)) != null){
              attributeValue = managerValue;
              //comment decache //context.decache(custom);
              //comment decache //context.decache(tempIdentity);
              found = true;
              break;
            }

          }
        }

      }
    }
  }
  logger.debug("returning manager :"+ attributeValue);
  return attributeValue;
